#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    for(int tc=0; tc<T; ++tc){
        int N; scanf("%d",&N);
        bool seen[1001] = {false};
        int order[10]; int sz=0;
        for(int i=0;i<N;++i){
            int task; scanf("%d",&task);
            if(!seen[task]){ seen[task]=true; order[sz++]=task; }
        }
        for(int i=0;i<sz;++i) printf("%d\n",order[i]);
        if(tc!=T-1) printf("\n");
    }
    return 0;
}

