import sys

def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for tc in range(T):
        N=int(next(it))
        seen=[False]*1001
        order=[]
        for _ in range(N):
            task=int(next(it))
            if not seen[task]:
                seen[task]=True
                order.append(task)
        out.extend(str(x) for x in order)
        if tc!=T-1:
            out.append('')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

